typedef struct {
    float weight;
    long assign;
    float cost;
} Point_Struct;

inline float d_dist_to_x(int p1,
                         int num,
                         int dim,
                         __global const float *coord_d,
                         __local const float *x_coord)
{
    float retval = 0.0f;
    for (int i = 0; i < dim; i++) {
        float tmp = coord_d[i * num + p1] - x_coord[i];
        retval += tmp * tmp;
    }
    return retval;
}

inline void compute_cost_body(__global const Point_Struct *p,
                              __global const float *coord_d,
                              __global float *work_mem_d,
                              __global const int *center_table_d,
                              __global char *switch_membership_d,
                              __local float *x_coord,
                              int num,
                              int dim,
                              long x,
                              int K)
{
    int gid = (int)get_global_id(0);
    int lid = (int)get_local_id(0);
    int lsize = (int)get_local_size(0);
    int x_idx = (int)x;

    for (int i = lid; i < dim; i += lsize) {
        x_coord[i] = coord_d[i * num + x_idx];
    }
    barrier(CLK_LOCAL_MEM_FENCE);

    if (gid < num) {
        int stride = K + 1;
        __global float *lower = work_mem_d + gid * stride;

        float x_cost = d_dist_to_x(gid, num, dim, coord_d, x_coord) * p[gid].weight;

        if (x_cost < p[gid].cost) {
            switch_membership_d[gid] = '1';
            lower[K] += x_cost - p[gid].cost;
        } else {
            int assign = (int)p[gid].assign;
            lower[center_table_d[assign]] += p[gid].cost - x_cost;
        }
    }
}

__kernel void dummy_compute_cost(__global const Point_Struct *p,
                                 __global const float *coord_d,
                                 __global float *work_mem_d,
                                 __global const int *center_table_d,
                                 __global char *switch_membership_d,
                                 __local float *x_coord,
                                 int num,
                                 int dim,
                                 long x,
                                 int K)
{
    compute_cost_body(p, coord_d, work_mem_d, center_table_d,
                      switch_membership_d, x_coord, num, dim, x, K);
}

__kernel void kernel_compute_cost(__global const Point_Struct *p,
                                  __global const float *coord_d,
                                  __global float *work_mem_d,
                                  __global const int *center_table_d,
                                  __global char *switch_membership_d,
                                  __local float *x_coord,
                                  int num,
                                  int dim,
                                  long x,
                                  int K)
{
    compute_cost_body(p, coord_d, work_mem_d, center_table_d,
                      switch_membership_d, x_coord, num, dim, x, K);
}
